class Solution:
    def pathExistenceQueries(self, n, nums, maxDiff, queries):
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        for i in range(n - 1):
            if abs(nums[i] - nums[i + 1]) <= maxDiff:
                ra, rb = find(i), find(i + 1)
                if ra != rb:
                    parent[ra] = rb
        return [find(u) == find(v) for u, v in queries]

