class Solution:
    def pathExistenceQueries(self, n, nums, maxDiff, queries):
        comp = [0] * n
        c = 0
        for i in range(1, n):
            if nums[i] - nums[i - 1] > maxDiff:
                c += 1
            comp[i] = c
        return [comp[u] == comp[v] for u, v in queries]

